using Microsoft.Extensions.ML;
using Microsoft.ML;
using TicketClassifier.Models;
using TicketClassifier.Services;

var builder = WebApplication.CreateBuilder(args);
builder.Services.AddControllers();
builder.Services.AddSingleton<ModelTrainerService>();

// Train the model before building so the file exists for the pool
var modelPath = TrainInitialModel(builder.Environment.ContentRootPath);
builder.Services.AddPredictionEnginePool<TicketInput, TicketPrediction>()
    .FromFile(modelPath);

var app = builder.Build();
app.MapControllers();
app.Run();

static string TrainInitialModel(string contentRoot)
{
    var mlContext = new MLContext(seed: 42);
    var dataPath = Path.Combine(contentRoot, "Data", "tickets.csv");
    var modelPath = Path.Combine(contentRoot, "Data", "model.zip");

    var data = mlContext.Data.LoadFromTextFile<TicketInput>(
        dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

    var pipeline = mlContext.Transforms.Text
            .FeaturizeText("SubjectFeatures", nameof(TicketInput.Subject))
        .Append(mlContext.Transforms.Text
            .FeaturizeText("DescriptionFeatures", nameof(TicketInput.Description)))
        .Append(mlContext.Transforms.Concatenate("Features",
            "SubjectFeatures", "DescriptionFeatures", nameof(TicketInput.Priority)))
        .Append(mlContext.Transforms.Conversion
            .MapValueToKey("Label", nameof(TicketInput.Category)))
        .Append(mlContext.MulticlassClassification.Trainers
            .SdcaMaximumEntropy("Label", "Features"))
        .Append(mlContext.Transforms.Conversion
            .MapKeyToValue("PredictedLabel"));

    var model = pipeline.Fit(data);
    mlContext.Model.Save(model, data.Schema, modelPath);

    Console.WriteLine($"Model trained and saved to {modelPath}");
    return modelPath;
}

