public TrainingMetrics TrainAndEvaluate()
{
    var data = _mlContext.Data.LoadFromTextFile<TicketInput>(
        _dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

    var pipeline = BuildPipeline();

    // Cross-validate on the full dataset (better than train/test split for small datasets)
    var cvResults = _mlContext.MulticlassClassification
        .CrossValidate(data, pipeline, numberOfFolds: 3, labelColumnName: "Label");

    var result = new TrainingMetrics
    {
        MicroAccuracy = Sanitize(cvResults.Average(r => r.Metrics.MicroAccuracy)),
        MacroAccuracy = Sanitize(cvResults.Average(r => r.Metrics.MacroAccuracy)),
        LogLoss = Sanitize(cvResults.Average(r => r.Metrics.LogLoss)),
        LogLossReduction = Sanitize(cvResults.Average(r => r.Metrics.LogLossReduction))
    };

    _logger.LogInformation(
        "Model trained — MicroAccuracy: {Micro:F4}, MacroAccuracy: {Macro:F4}, LogLoss: {LogLoss:F4}",
        result.MicroAccuracy, result.MacroAccuracy, result.LogLoss);

    // Retrain on full dataset for the production model
    var model = pipeline.Fit(data);
    _mlContext.Model.Save(model, data.Schema, _modelPath);
    _logger.LogInformation("Model saved to {Path}", _modelPath);

    return result;
}

